@dataclass(frozen=True)
class ImageKind:
    key: str
    mime: str
    ext: str
    pillow_format: str
    aliases: tuple[str, ...]


KINDS = {
    "jpeg": ImageKind("jpeg", "image/jpeg", ".jpg", "JPEG", ("image/jpeg", "image/pjpeg")),
    "png": ImageKind("png", "image/png", ".png", "PNG", ("image/png", "image/x-png")),
    "gif": ImageKind("gif", "image/gif", ".gif", "GIF", ("image/gif",)),
    "webp": ImageKind("webp", "image/webp", ".webp", "WEBP", ("image/webp",)),
}

EXT_TO_KIND = {
    ".jpg": "jpeg",
    ".jpeg": "jpeg",
    ".jfif": "jpeg",
    ".png": "png",
    ".gif": "gif",
    ".webp": "webp",
}

GENERIC_CONTENT_TYPES = {"application/octet-stream", "binary/octet-stream"}
ALLOWED_DECLARED_TYPES = {alias for kind in KINDS.values() for alias in kind.aliases}


def detect_image_type(buf: bytes) -> Optional[ImageKind]:
    # Magic-byte validation prevents trusting spoofed Content-Type or extension.
    if len(buf) >= 8 and buf.startswith(b"\x89PNG\r\n\x1a\n"):
        return KINDS["png"]
    if len(buf) >= 3 and buf.startswith(b"\xff\xd8\xff"):
        return KINDS["jpeg"]
    if len(buf) >= 6 and buf[:6] in (b"GIF87a", b"GIF89a"):
        return KINDS["gif"]
    if len(buf) >= 12 and buf[:4] == b"RIFF" and buf[8:12] == b"WEBP":
        return KINDS["webp"]
    return None


def verify_image_file(path: Path, expected: ImageKind) -> tuple[int, int]:
    # Pillow verification catches truncated/corrupt files and decompression bombs.
    try:
        with Image.open(path) as img:
            if img.format != expected.pillow_format:
                raise UploadError(
                    415,
                    "image_format_mismatch",
                    "Magic bytes and decoded image format do not match.",
                    {"expected": expected.pillow_format, "actual": img.format},
