            width, height = img.size
            if width <= 0 or height <= 0:
                raise UploadError(400, "invalid_image_dimensions", "Image dimensions are invalid.")

            if width * height > MAX_IMAGE_PIXELS:
                raise UploadError(
                    413,
                    "image_dimensions_too_large",
                    "Image dimensions are too large.",
                    {"max_pixels": MAX_IMAGE_PIXELS},
                )

            img.verify()
            return width, height

    except Image.DecompressionBombWarning as exc:
        raise UploadError(413, "image_too_many_pixels", "Image is too large to decode safely.") from exc
    except Image.DecompressionBombError as exc:
        raise UploadError(413, "image_too_many_pixels", "Image is too large to decode safely.") from exc
    except UnidentifiedImageError as exc:
        raise UploadError(400, "corrupt_image", "Uploaded file is not a valid image.") from exc
    except OSError as exc:
        raise UploadError(400, "corrupt_image", "Uploaded image is truncated or corrupt.") from exc


# ----------------------------
# Filename / storage safety
# ----------------------------

CONTROL_RE = re.compile(r"[\x00-\x1f\x7f]")
SAFE_STEM_RE = re.compile(r"[^A-Za-z0-9_-]+")
WINDOWS_RESERVED = {
    "CON", "PRN", "AUX", "NUL",
    *(f"COM{i}" for i in range(1, 10)),
    *(f"LPT{i}" for i in range(1, 10)),
}


def sanitize_filename(raw: str) -> tuple[str, Optional[str]]:
    # Handles path traversal, null bytes, control chars, Unicode normalization,
    # double extensions, reserved device names, and overly long filenames.
    if raw is None or raw == "":
        raise UploadError(400, "missing_filename", "File part is missing a filename.")

    if len(raw.encode("utf-8", "replace")) > MAX_ORIGINAL_FILENAME_BYTES:
        raise UploadError(400, "filename_too_long", "Filename is too long.")

    normalized = unicodedata.normalize("NFKC", raw)
    if CONTROL_RE.search(normalized):
        raise UploadError(400, "invalid_filename", "Filename contains control characters.")

    normalized = normalized.replace("\\", "/")
    basename = normalized.rsplit("/", 1)[-1].strip().strip(" .")
    if basename in {"", ".", ".."}:
        raise UploadError(400, "invalid_filename", "Filename is invalid.")

    stem, ext = os.path.splitext(basename)
    ext = ext.lower()

    if ext and ext not in EXT_TO_KIND:
        raise UploadError(
            415,
            "unsupported_filename_extension",
            "Filename extension is not an allowed image type.",
            {"allowed_extensions": sorted(EXT_TO_KIND)},
        )

    # Replace dots in the stem to avoid storing names like `avatar.php.jpg`.
    stem = stem.replace(".", "_")
    stem = SAFE_STEM_RE.sub("_", stem).strip("_-") or "upload"

    if stem.upper() in WINDOWS_RESERVED:
        stem = "upload"

    stem = stem[:MAX_STEM_CHARS].strip("_-") or "upload"
    return stem, EXT_TO_KIND.get(ext)


def normalize_content_type(value: Optional[str]) -> Optional[str]:
    if not value:
        return None
    return value.split(";", 1)[0].strip().lower() or None


def storage_error(exc: OSError, default_code: str = "storage_error") -> UploadError:
    if exc.errno == errno.ENOSPC:
        return UploadError(500, "disk_full", "Server storage is full.")
    if exc.errno in {errno.EACCES, errno.EPERM, errno.EROFS}:
        return UploadError(500, "storage_permission_denied", "Server cannot write to upload storage.")
    return UploadError(500, default_code, "Server failed while storing the upload.")


def ensure_storage_ready() -> None:
    try:
        UPLOAD_DIR.mkdir(parents=True, exist_ok=True)
        TMP_DIR.mkdir(parents=True, exist_ok=True)
        os.chmod(UPLOAD_DIR, 0o700)
        os.chmod(TMP_DIR, 0o700)
    except OSError as exc:
        raise storage_error(exc, "storage_unavailable") from exc

    if not UPLOAD_DIR.is_dir() or not TMP_DIR.is_dir():
        raise UploadError(500, "storage_unavailable", "Upload storage path is not a directory.")

    try:
        free = shutil.disk_usage(UPLOAD_DIR).free
    except OSError as exc:
        raise storage_error(exc, "storage_unavailable") from exc

    if free < MAX_FILE_BYTES + RESERVED_FREE_BYTES:
        raise UploadError(500, "insufficient_storage", "Server does not have enough free disk space.")


def fsync_directory(path: Path) -> None:
    if os.name == "nt":
        return
    fd = os.open(path, os.O_RDONLY | getattr(os, "O_DIRECTORY", 0))
    try:
        os.fsync(fd)
    finally:
        os.close(fd)


def cleanup_stale_temp_files(max_age_seconds: int = 24 * 60 * 60) -> None:
    # If the server restarts mid-upload, only `.part` files remain; remove old ones.
    now = time.time()
    for path in TMP_DIR.glob(".upload-*.part"):
        try:
            if path.is_file() and now - path.stat().st_mtime > max_age_seconds:
                path.unlink()
        except OSError:
            logger.warning("failed_to_cleanup_stale_upload_temp", exc_info=True)


# ----------------------------
# Upload state
# ----------------------------

@dataclass
class UploadContext:
    request_id: str
    original_filename: Optional[str] = None
    safe_stem: str = "upload"
    original_extension_kind: Optional[str] = None
    declared_content_type: Optional[str] = None

    detected: Optional[ImageKind] = None
    pending_magic: bytearray = field(default_factory=bytearray)

    size: int = 0
    raw_request_bytes: int = 0
    sha256: Any = field(default_factory=hashlib.sha256)

    tmp_path: Optional[Path] = None
    tmp_fd: Optional[int] = None
    final_path: Optional[Path] = None
    final_filename: Optional[str] = None

    file_seen: bool = False
    file_closed: bool = False
    width: Optional[int] = None
    height: Optional[int] = None

    def begin_file(self, filename: str, declared_content_type: Optional[str]) -> None:
        if self.file_seen:
            raise UploadError(400, "multiple_files", "Exactly one file may be uploaded.")
        self.file_seen = True

        self.original_filename = filename
        self.safe_stem, self.original_extension_kind = sanitize_filename(filename)
        self.declared_content_type = normalize_content_type(declared_content_type)

        if (
            self.declared_content_type
            and self.declared_content_type not in GENERIC_CONTENT_TYPES
            and self.declared_content_type not in ALLOWED_DECLARED_TYPES
        ):
            raise UploadError(
                415,
                "unsupported_declared_type",
                "Declared Content-Type is not an allowed image type.",
                {"declared_content_type": self.declared_content_type},
            )

    def accept_file_data(self, data: bytes) -> None:
        if self.file_closed:
            raise UploadError(400, "data_after_file_end", "Received file bytes after file part ended.")

        if not data:
            return

        if self.size + len(data) > MAX_FILE_BYTES:
            raise UploadError(
                413,
                "file_too_large",
                "Uploaded file exceeds the 10MB limit.",
                {"max_bytes": MAX_FILE_BYTES},
            )

        self.size += len(data)
        self.sha256.update(data)

        if self.detected is None:
            self.pending_magic.extend(data)
            kind = detect_image_type(bytes(self.pending_magic))

            if kind:
                self._accept_detected_type(kind)
                self._open_temp_file()
                self._write_all(bytes(self.pending_magic))
                self.pending_magic.clear()
            elif len(self.pending_magic) >= MAGIC_SCAN_BYTES:
                raise UploadError(415, "unsupported_image_type", "File magic bytes are not JPEG, PNG, GIF, or WebP.")
            return

        self._write_all(data)

    def end_file(self) -> None:
        if self.size == 0:
            raise UploadError(400, "empty_file", "Uploaded file is empty.")

        if self.detected is None:
            raise UploadError(415, "unsupported_image_type", "File is too short or has unsupported magic bytes.")

        if self.tmp_fd is None or self.tmp_path is None:
            raise UploadError(500, "storage_write_failed", "Upload temp file was not created.")

        self._fsync_and_close()
        self.width, self.height = verify_image_file(self.tmp_path, self.detected)
        self.file_closed = True

    def commit(self) -> None:
        if not self.file_closed or not self.tmp_path or not self.detected:
            raise UploadError(400, "incomplete_upload", "Upload did not complete.")

        self.final_filename = f"{uuid.uuid4().hex}_{self.safe_stem}{self.detected.ext}"
        final_path = UPLOAD_DIR / self.final_filename

        try:
            # Atomic publish: temp file is private until this rename succeeds.
            os.replace(self.tmp_path, final_path)
            self.tmp_path = None
            self.final_path = final_path
            fsync_directory(UPLOAD_DIR)
        except OSError as exc:
            if self.final_path:
                try:
                    self.final_path.unlink()
                except OSError:
                    pass
            raise storage_error(exc, "storage_commit_failed") from exc

    def cleanup(self) -> None:
        # Removes partial writes on validation failure, dropped connections, or disk errors.
        if self.tmp_fd is not None:
            try:
                os.close(self.tmp_fd)
            except OSError:
                pass
            self.tmp_fd = None

        if self.tmp_path is not None:
            try:
                self.tmp_path.unlink(missing_ok=True)
            except OSError:
                logger.warning("failed_to_cleanup_upload_temp", exc_info=True)
            self.tmp_path = None

    def _accept_detected_type(self, kind: ImageKind) -> None:
        if self.original_extension_kind and self.original_extension_kind != kind.key:
            raise UploadError(
                415,
                "extension_mismatch",
                "Filename extension does not match detected image type.",
                {"extension_type": self.original_extension_kind, "detected_type": kind.key},
            )

        if (
            self.declared_content_type
            and self.declared_content_type not in GENERIC_CONTENT_TYPES
            and self.declared_content_type not in kind.aliases
        ):
            raise UploadError(
                415,
                "content_type_mismatch",
                "Declared Content-Type does not match detected image type.",
                {"declared_content_type": self.declared_content_type, "detected_mime": kind.mime},
            )

        self.detected = kind

    def _open_temp_file(self) -> None:
        ensure_storage_ready()
        name = f".upload-{self.request_id}-{uuid.uuid4().hex}.part"
        self.tmp_path = TMP_DIR / name

        try:
            self.tmp_fd = os.open(self.tmp_path, os.O_WRONLY | os.O_CREAT | os.O_EXCL, 0o600)
        except OSError as exc:
            raise storage_error(exc, "storage_open_failed") from exc

    def _write_all(self, data: bytes) -> None:
        if self.tmp_fd is None:
            raise UploadError(500, "storage_write_failed", "Upload temp file is not open.")

        view = memoryview(data)
        while view:
            try:
                written = os.write(self.tmp_fd, view)
            except OSError as exc:
                raise storage_error(exc, "storage_write_failed") from exc

            if written == 0:
                raise UploadError(500, "storage_write_failed", "Disk write returned zero bytes.")

            view = view[written:]

    def _fsync_and_close(self) -> None:
        assert self.tmp_fd is not None
        try:
            os.fsync(self.tmp_fd)
        except OSError as exc:
            raise storage_error(exc, "storage_fsync_failed") from exc
        finally:
            try:
                os.close(self.tmp_fd)
            finally:
                self.tmp_fd = None


# ----------------------------
# Multipart parsing
# ----------------------------

@dataclass
class PartState:
    headers: dict[str, str] = field(default_factory=dict)
    header_field: bytearray = field(default_factory=bytearray)
    header_value: bytearray = field(default_factory=bytearray)
    header_bytes: int = 0
    is_file: bool = False
    field_name: Optional[str] = None
    field_bytes: int = 0


def option_text(options: dict[Any, Any], *names: str) -> Optional[str]:
    for name in names:
        for key in (name, name.encode("ascii")):
            if key in options:
                value = options[key]
                text = value.decode("utf-8", "replace") if isinstance(value, bytes) else str(value)

                if name.endswith("*") and "''" in text:
                    charset, _, encoded = text.partition("''")
                    return urllib.parse.unquote(encoded, encoding=charset or "utf-8", errors="replace")

                return text
    return None


def parse_boundary(request: Request) -> bytes:
    content_type = request.headers.get("content-type")
    if not content_type:
        raise UploadError(400, "missing_content_type", "Request must be multipart/form-data.")

    media_type, options = parse_options_header(content_type.encode("latin-1", "replace"))
    media_type_text = media_type.decode("latin-1") if isinstance(media_type, bytes) else str(media_type)

    if media_type_text.lower() != "multipart/form-data":
        raise UploadError(415, "unsupported_media_type", "Request Content-Type must be multipart/form-data.")

    boundary = options.get(b"boundary") or options.get("boundary")
    if isinstance(boundary, str):
        boundary = boundary.encode("latin-1", "replace")

    if not boundary:
        raise UploadError(400, "missing_multipart_boundary", "Multipart boundary is missing.")
    if len(boundary) > 200:
        raise UploadError(400, "invalid_multipart_boundary", "Multipart boundary is too long.")

    content_length = request.headers.get("content-length")
    if content_length is not None:
        try:
            length = int(content_length)
        except ValueError as exc:
            raise UploadError(400, "invalid_content_length", "Content-Length is invalid.") from exc

        if length <= 0:
            raise UploadError(400, "empty_request", "Request body is empty.")
        if length > MAX_REQUEST_BYTES:
            raise UploadError(
                413,
                "request_too_large",
                "Request exceeds maximum allowed upload size.",
                {"max_request_bytes": MAX_REQUEST_BYTES},
            )

    return boundary


def make_parser(boundary: bytes, ctx: UploadContext) -> MultipartParser:
    part = PartState()
    part_count = 0
    field_count = 0

    def on_part_begin() -> None:
        nonlocal part, part_count
        part_count += 1
        if part_count > MAX_FORM_PARTS:
            raise UploadError(400, "too_many_parts", "Too many multipart sections.")
        part = PartState()

    def on_header_field(data: bytes, start: int, end: int) -> None:
        part.header_bytes += end - start
        if part.header_bytes > MAX_PART_HEADER_BYTES:
            raise UploadError(400, "multipart_headers_too_large", "Multipart part headers are too large.")
        part.header_field.extend(data[start:end])

    def on_header_value(data: bytes, start: int, end: int) -> None:
        part.header_bytes += end - start
        if part.header_bytes > MAX_PART_HEADER_BYTES:
            raise UploadError(400, "multipart_headers_too_large", "Multipart part headers are too large.")
        part.header_value.extend(data[start:end])

    def on_header_end() -> None:
        name = bytes(part.header_field).decode("latin-1", "replace").strip().lower()
        value = bytes(part.header_value).decode("latin-1", "replace").strip()

        if not name or not re.fullmatch(r"[a-z0-9!#$%&'*+.^_`|~-]+", name):
            raise UploadError(400, "invalid_multipart_header", "Multipart header name is invalid.")

        part.headers[name] = value
        part.header_field.clear()
        part.header_value.clear()

    def on_headers_finished() -> None:
        nonlocal field_count

        disposition = part.headers.get("content-disposition")
        if not disposition:
            raise UploadError(400, "missing_content_disposition", "Multipart part lacks Content-Disposition.")

        disp, options = parse_options_header(disposition.encode("latin-1", "replace"))
        disp_text = disp.decode("latin-1") if isinstance(disp, bytes) else str(disp)

        if disp_text.lower() != "form-data":
            raise UploadError(400, "invalid_content_disposition", "Multipart part must be form-data.")

        field_name = option_text(options, "name")
        filename = option_text(options, "filename", "filename*")
        if not field_name:
            raise UploadError(400, "missing_field_name", "Multipart field name is missing.")

        transfer_encoding = part.headers.get("content-transfer-encoding")
        if transfer_encoding and transfer_encoding.lower() not in {"binary", "8bit"}:
            raise UploadError(415, "unsupported_transfer_encoding", "Encoded multipart file bodies are not accepted.")

        part.field_name = field_name
        part.is_file = filename is not None

        if part.is_file:
            if field_name != "file":
                raise UploadError(400, "unexpected_file_field", "File must be uploaded in the 'file' field.")
            ctx.begin_file(filename or "", part.headers.get("content-type"))
        else:
            if field_name == "file":
                raise UploadError(400, "missing_filename", "The 'file' field must contain a file upload.")
            field_count += 1
            if field_count > MAX_FORM_FIELDS:
                raise UploadError(400, "too_many_fields", "Too many form fields.")

    def on_part_data(data: bytes, start: int, end: int) -> None:
        chunk = data[start:end]

        if part.is_file:
            ctx.accept_file_data(chunk)
            return

        part.field_bytes += len(chunk)
        if part.field_bytes > MAX_FIELD_BYTES:
            raise UploadError(400, "field_too_large", "A non-file form field is too large.")

    def on_part_end() -> None:
        if part.is_file:
            ctx.end_file()

    return MultipartParser(
        boundary,
        {
            "on_part_begin": on_part_begin,
            "on_header_field": on_header_field,
            "on_header_value": on_header_value,
            "on_header_end": on_header_end,
            "on_headers_finished": on_headers_finished,
            "on_part_data": on_part_data,
            "on_part_end": on_part_end,
        },
    )


