@asynccontextmanager
async def lifespan(app: FastAPI):
    ensure_storage_ready()
    cleanup_stale_temp_files()
    yield


app = FastAPI(lifespan=lifespan)


async def acquire_upload_slot() -> bool:
    # Concurrency guard prevents too many simultaneous disk writers.
    try:
        await asyncio.wait_for(upload_semaphore.acquire(), timeout=UPLOAD_SLOT_TIMEOUT_SECONDS)
        return True
    except asyncio.TimeoutError:
        return False


@app.post("/api/upload")
async def upload_image(request: Request) -> JSONResponse:
    request_id = uuid.uuid4().hex
    started_at = time.monotonic()
    ctx = UploadContext(request_id=request_id)
    slot_acquired = False

    try:
        slot_acquired = await acquire_upload_slot()
        if not slot_acquired:
            exc = UploadError(503, "server_busy", "Too many uploads are in progress. Try again later.")
            log_attempt(request, request_id, "failure", exc.status_code, started_at, ctx, exc.code)
            return error_response(exc, request_id)

        boundary = parse_boundary(request)
        parser = make_parser(boundary, ctx)

        # Stream request body in chunks. The full upload is never read into memory.
        async for chunk in request.stream():
            if not chunk:
                continue

            ctx.raw_request_bytes += len(chunk)
            if ctx.raw_request_bytes > MAX_REQUEST_BYTES:
                raise UploadError(
                    413,
                    "request_too_large",
                    "Request exceeds maximum allowed upload size.",
                    {"max_request_bytes": MAX_REQUEST_BYTES},
                )

            parser.write(chunk)

        parser.finalize()

        if not ctx.file_seen:
            raise UploadError(400, "missing_file", "Request must include exactly one file field named 'file'.")
        if not ctx.file_closed:
            raise UploadError(400, "incomplete_upload", "File upload did not complete.")

        ctx.commit()

        log_attempt(request, request_id, "success", 201, started_at, ctx)
        return JSONResponse(
            status_code=201,
            content={
                "ok": True,
                "request_id": request_id,
                "file": {
                    "filename": ctx.final_filename,
                    "content_type": ctx.detected.mime if ctx.detected else None,
                    "size_bytes": ctx.size,
                    "sha256": ctx.sha256.hexdigest(),
                    "width": ctx.width,
                    "height": ctx.height,
                },
            },
        )

    except UploadError as exc:
        ctx.cleanup()
        log_attempt(request, request_id, "failure", exc.status_code, started_at, ctx, exc.code)
        return error_response(exc, request_id)

    except MultipartParseError as exc:
        ctx.cleanup()
        wrapped = UploadError(400, "malformed_multipart", "Multipart body is malformed.")
        log_attempt(request, request_id, "failure", wrapped.status_code, started_at, ctx, wrapped.code)
        return error_response(wrapped, request_id)

    except ClientDisconnect as exc:
        ctx.cleanup()
        wrapped = UploadError(400, "client_disconnected", "Client disconnected before upload completed.")
        log_attempt(request, request_id, "failure", wrapped.status_code, started_at, ctx, wrapped.code)
        return error_response(wrapped, request_id)

    except Exception:
        ctx.cleanup()
        logger.exception("unexpected_upload_failure")
        wrapped = UploadError(500, "internal_error", "Unexpected server error while processing upload.")
        log_attempt(request, request_id, "failure", wrapped.status_code, started_at, ctx, wrapped.code)
        return error_response(wrapped, request_id)

    finally:
        if slot_acquired:
            upload_semaphore.release()


if __name__ == "__main__":
    import uvicorn

    uvicorn.run("upload_app:app", host="0.0.0.0", port=8000, reload=False)
